mapper.select:
SELECT id, item_code, stage_code, question_type, ability_type, word_text, stem_text, stem_audio_url, stem_image_url, difficulty_score, discrimination_score, is_anchor, review_status, bank_version, content_source, status, created_at, updated_at FROM assessment_item WHERE stage_code = #{stageCode} AND bank_version = #{bankVersion} AND is_anchor = #{isAnchor} AND review_status = 'APPROVED' AND status = 1 AND difficulty_score BETWEEN #{minDifficulty} AND #{maxDifficulty}
AND id NOT IN
#{itemId}
ORDER BY ABS(difficulty_score - #{targetDifficulty}) ASC, difficulty_score ASC, id ASC LIMIT #{limitSize}
